external_knowledge:
- Major offenses refer to crimes with more than 1000 reported cases; 
- Offenses against the public are categorized separately and are excluded from the results;
- The names of the crimes are represented in uppercase letters for emphasis.

sql:
SELECT incidents.incident_id, incidents.date_occurred, incidents.crime_description, locations.location_name
FROM incidents
JOIN locations ON incidents.location_id = locations.location_id;

SELECT disposition 
FROM incidents 
WHERE incident_id = '0';

SELECT incident_id, date_reported, date_occurred, crime_description 
FROM incidents 
WHERE disposition = 'STUDENT DISCIPLINE REFERRAL';

external_knowledge:
- 'stormy' metaphorically refers to areas with a high number of incidents;
- 'tempests' are incidents that occurred;
- 'calmed' implies incidents being resolved;
- 'fully settled' corresponds to incidents with a 'closed' status;
- 'peace-making effort' is metaphorical for the resolution rate of incidents.

sql:
SELECT agency_name
FROM law_enforcement_agencies
WHERE agency_id = 1;

SELECT agency_id, agency_name
FROM law_enforcement_agencies
WHERE jurisdiction = 'city';

SELECT COUNT(*)
FROM reporters
WHERE role = 'staff';

SELECT DISTINCT crime_name
FROM crime_types
INNER JOIN incidents ON crime_types.crime_type_id = incidents.incident_type_id;
